    int n = (int)a.size(), m = (int)b.size();
    vector<vector<int>> dp(n + 1, vector<int>(m + 1, 0));
    for (int i = 1; i <= n; i++)
    for (int j = 1; j <= m; j++)
    if (a[i - 1] == b[j - 1])
    dp[i][j] = dp[i - 1][j - 1] + 1;
    else
    ________; // 在此处填入选项
    return dp[n][m];
}
```

下列代码的时间复杂度（以 为自变量，忽略常数与低阶项）是（ ）。

```cpp
long long s = 0;
for (int i = 1; i <= n; i++) {
    for (int j = 1; j * j <= i; j++) {
        s += j;
    }
}
```

